import type { HTMLAttributes, ReactElement } from 'react';
/**
 * Варианты отображения панели вкладок.
 * - `default` — иконка + подпись (caption).
 * - `compact` — только иконка (меньший размер), подпись скрыта.
 */
export type TabbarType = 'default' | 'compact';
/**
 * Пропсы компонента Tabbar — контейнер нижней навигации.
 */
export interface TabbarProps extends HTMLAttributes<HTMLDivElement> {
    /**
     * Дополнительный CSS-класс для корневого элемента.
     */
    className?: string;
    /**
     * Вариант отображения панели.
     * @default 'default'
     */
    type?: TabbarType;
    /**
     * Дочерние элементы панели. Ожидаются только `TabbarItem`.
     * Можно передать один элемент или массив элементов.
     */
    children?: ReactElement | Array<ReactElement>;
}
